start                                 leax      >IcptRtn,pcr                              ; advance the working pointer to the next startup element.
                                      ldu       #$0000                                    ; fetch constant $0000 for the startup calculation.
                                      os9       F$Icpt                                    ; ask OS-9 to perform F$Icpt for this startup operation.
                                      orcc      #IntMasks                                 ; apply the constant IntMasks mask/flags required by startup.
                                      lds       #$5EE4                                    ; fetch constant $5EE4 for the startup calculation.
                                      andcc     #^Intmasks                                ; apply the constant ^Intmasks mask/flags required by startup.
                                      leax      >ScrnDev,pcr                              ; advance the working pointer to the next startup element.
* This code was patched to disallow opening /TERM.  This is so that the game
* can use the window/screen that it was forked from.
*         lda   #$03
                                      nop       Update                                    ; processor state as required by the surrounding startup algorithm.
                                      nop       Update                                    ; processor state as required by the surrounding startup algorithm.
*         os9   I$Open
                                      nop       Update                                    ; processor state as required by the surrounding startup algorithm.
                                      nop       Update                                    ; processor state as required by the surrounding startup algorithm.
                                      nop       Update                                    ; processor state as required by the surrounding startup algorithm.
*         lbcs  close_and_exit
                                      nop       Update                                    ; processor state as required by the surrounding startup algorithm.
                                      nop       Update                                    ; processor state as required by the surrounding startup algorithm.
                                      lda       #$01                                      ; fetch constant $01 for the startup calculation.
                                      sta       >stdout_path                              ; commit the updated startup value to stdout_path.
drain_startup_input                   lda       #$04                                      ; fetch constant $04 for the drain startup input calculation.
                                      lbsr      dispatch_file_operation                   ; invoke dispatch_file_operation and consume its documented result.
                                      bcc       drain_startup_input                       ; continue at drain_startup_input when this state test selects that path.
                                      lbsr      select_monitor_type                       ; invoke select_monitor_type and consume its documented result.
                                      lda       >monitor_type                             ; fetch monitor_type for the drain startup input calculation.
                                      pshs      a                                         ; preserve a across the following drain startup input work.
                                      lda       >stdout_path                              ; fetch stdout_path for the drain startup input calculation.
                                      ldb       #SS.Montr                                 ; fetch constant SS.Montr for the drain startup input calculation.
                                      ldx       >requested_monitor_type                   ; fetch requested_monitor_type for the drain startup input calculation.
                                      os9       I$SetStt                                  ; set monitor type
                                      lda       >stdout_path                              ; fetch stdout_path for the drain startup input calculation.
                                      ldb       #SS.AScrn                                 ; fetch constant SS.AScrn for the drain startup input calculation.
                                      ldx       #$0002                                    ; fetch constant $0002 for the drain startup input calculation.
                                      os9       I$SetStt                                  ; allocate screen
                                      lbcs      close_and_exit                            ; continue at close_and_exit when this state test selects that path.
                                      stx       >screen_base                              ; commit the updated drain startup input value to screen_base.
                                      sty       >screen_number                            ; commit the updated drain startup input value to screen_number.
                                      pshs      y,x                                       ; preserve y,x across the following drain startup input work.
                                      lda       >stdout_path                              ; fetch stdout_path for the drain startup input calculation.
                                      clrb                                                ; ss.Opt - reset the working drain startup input value before reuse.
                                      ldx       #$034F                                    ; fetch constant $034F for the drain startup input calculation.
                                      os9       I$GetStt                                  ; get options
                                      clr       >os9_state_field_011                      ; reset the working drain startup input value before reuse.
                                      clr       >os9_state_field_012                      ; reset the working drain startup input value before reuse.
                                      lda       >stdout_path                              ; fetch stdout_path for the drain startup input calculation.
                                      clrb                                                ; ss.Opt - reset the working drain startup input value before reuse.
                                      ldx       #$034F                                    ; fetch constant $034F for the drain startup input calculation.
                                      os9       I$SetStt                                  ; set options
                                      ldu       #$0500                                    ; fetch constant $0500 for the drain startup input calculation.
                                      leax      >CTitle,pcr                               ; advance the working pointer to the next drain startup input element.
                                      lda       #$01                                      ; fetch constant $01 for the drain startup input calculation.
                                      lbsr      dispatch_file_operation                   ; invoke dispatch_file_operation and consume its documented result.
                                      lbsr      decode_loaded_title                       ; invoke decode_loaded_title and consume its documented result.
                                      ldy       >screen_number                            ; fetch screen_number for the drain startup input calculation.
                                      lda       >stdout_path                              ; fetch stdout_path for the drain startup input calculation.
                                      ldb       #SS.DScrn                                 ; fetch constant SS.DScrn for the drain startup input calculation.
                                      os9       I$SetStt                                  ; display screen
                                      lbcs      startup_error_unwind                      ; continue at startup_error_unwind when this state test selects that path.
                                      ldy       #$0382                                    ; fetch constant $0382 for the drain startup input calculation.
                                      ldd       #$FF0F                                    ; fetch constant $FF0F for the drain startup input calculation.
startup_step_001                      sta       b,y                                       ; commit the updated startup 001 value to b,y.
                                      decb                                                ; advance the startup 001 counter toward its next transition.
                                      bpl       startup_step_001                          ; continue at startup_step_001 when this state test selects that path.
                                      leay      >title_palette,pcr                        ; advance the working pointer to the next startup 001 element.
                                      lbsr      install_palette                           ; invoke install_palette and consume its documented result.
                                      ldu       #$0500                                    ; fetch constant $0500 for the startup 001 calculation.
                                      leax      >CRobot,pcr                               ; advance the working pointer to the next startup 001 element.
                                      lda       #$01                                      ; fetch constant $01 for the startup 001 calculation.
                                      lbsr      dispatch_file_operation                   ; invoke dispatch_file_operation and consume its documented result.
                                      pshs      y                                         ; preserve y across the following startup 001 work.
                                      lda       #$30                                      ; fetch constant $30 for the startup 001 calculation.
                                      sta       >tone_volume                              ; commit the updated startup 001 value to tone_volume.
                                      clra                                                ; reset the working startup 001 value before reuse.
                                      lbsr      play_sound_effect                         ; invoke play_sound_effect and consume its documented result.
                                      leay      >composite_palette,pcr                    ; advance the working pointer to the next startup 001 element.
                                      lda       >monitor_type                             ; fetch monitor_type for the startup 001 calculation.
                                      ldb       #$10                                      ; fetch constant $10 for the startup 001 calculation.
                                      mul                                                 ; form the unsigned product used by the startup 001 lookup or projection.
                                      leay      d,y                                       ; advance the working pointer to the next startup 001 element.
                                      bsr       install_palette                           ; invoke install_palette and consume its documented result.
                                      puls      y                                         ; restore y; including PC returns when requested.
                                      bsr       decode_loaded_title                       ; invoke decode_loaded_title and consume its documented result.
                                      clra                                                ; reset the working startup 001 value before reuse.
                                      ldu       #$0000                                    ; fetch constant $0000 for the startup 001 calculation.
                                      ldy       #$2869                                    ; fetch constant $2869 for the startup 001 calculation.
                                      leax      >KorVar,pcr                               ; advance the working pointer to the next startup 001 element.
                                      lbsr      dispatch_file_operation                   ; invoke dispatch_file_operation and consume its documented result.
                                      puls      y,x                                       ; restore y,x; including PC returns when requested.
                                      stx       >screen_base                              ; commit the updated startup 001 value to screen_base.
                                      sty       >screen_number                            ; commit the updated startup 001 value to screen_number.
                                      puls      a                                         ; restore a; including PC returns when requested.
                                      sta       >monitor_type                             ; commit the updated startup 001 value to monitor_type.
                                      lbra      game_controller                           ; continue at game_controller; this path does not fall through.
wait_for_joystick_press               ldd       #SS.Joy                                   ; fetch constant SS.Joy for the wait for joystick press calculation.
                                      ldx       #$0001                                    ; fetch constant $0001 for the wait for joystick press calculation.
                                      os9       I$GetStt                                  ; get joystick values
                                      tsta                                                ; test  to choose the next wait for joystick press state.
                                      beq       wait_for_joystick_press                   ; continue at wait_for_joystick_press when this state test selects that path.
                                      rts                                                 ; return the completed wait for joystick press result to the caller.
set_palette_entry                     pshs      u,y,x,b,a                                 ; preserve u,y,x,b,a across the following set palette entry work.
set_palette_entry_inner               ldx       #$0382                                    ; fetch constant $0382 for the set palette entry inner calculation.
                                      cmpa      b,x                                       ; test b,x to choose the next set palette entry inner state.
                                      beq       palette_entry_done                        ; continue at palette_entry_done when this state test selects that path.
                                      sta       b,x                                       ; commit the updated set palette entry inner value to b,x.
                                      ldy       #$1B31                                    ; palette escape code
                                      sty       >palette_escape_packet                    ; commit the updated set palette entry inner value to palette_escape_packet.
                                      stb       >os9_state_field_009                      ; commit the updated set palette entry inner value to os9_state_field_009.
                                      sta       >os9_state_field_010                      ; commit the updated set palette entry inner value to os9_state_field_010.
                                      ldx       #$034B                                    ; fetch constant $034B for the set palette entry inner calculation.
                                      ldy       #$0004                                    ; fetch constant $0004 for the set palette entry inner calculation.
                                      lda       #$01                                      ; fetch constant $01 for the set palette entry inner calculation.
                                      os9       I$Write                                   ; write palette escape sequence
palette_entry_done                    puls      pc,u,y,x,b,a                              ; restore pc,u,y,x,b,a; including PC returns when requested.
set_object_palette_entry              pshs      u,y,x,b,a                                 ; preserve u,y,x,b,a across the following set object palette entry work.
                                      pshs      a                                         ; preserve a across the following set object palette entry work.
                                      tfr       x,d                                       ; reshape the working value/registers for set object palette entry arithmetic.
                                      addb      #$05                                      ; fold constant $05 into the current set object palette entry accumulator.
                                      puls      a                                         ; restore a; including PC returns when requested.
                                      bra       set_palette_entry_inner                   ; continue at set_palette_entry_inner when this state test selects that path.
install_palette                       ldb       #$0F                                      ; fetch constant $0F for the install palette calculation.
palette_install_loop                  lda       b,y                                       ; fetch b,y for the palette install loop calculation.
                                      bsr       set_palette_entry                         ; invoke set_palette_entry and consume its documented result.
                                      decb                                                ; advance the palette install loop counter toward its next transition.
                                      bpl       palette_install_loop                      ; continue at palette_install_loop when this state test selects that path.
                                      rts                                                 ; return the completed palette install loop result to the caller.
decode_loaded_title                   ldu       >screen_base                              ; fetch screen_base for the decode loaded title calculation.
                                      ldx       #$0500                                    ; fetch constant $0500 for the decode loaded title calculation.
                                      lbra      decode_rle_image                          ; continue at decode_rle_image; this path does not fall through.

* Intercept routine - merely return
IcptRtn                               rti                                                 ; return the completed decode loaded title result to the caller.

                                      ldd       #$0000                                    ; fetch constant $0000 for the decode loaded title calculation.
startup_error_unwind                  puls      y,x,a                                     ; restore y,x,a; including PC returns when requested.
close_and_exit                        lda       #$03                                      ; fetch constant $03 for the close and exit calculation.
                                      lbra      dispatch_file_operation                   ; continue at dispatch_file_operation; this path does not fall through.
select_monitor_type                   clr       >requested_monitor_type                   ; reset the working select monitor type value before reuse.
redraw_monitor_prompt                 lbsr      clear_terminal                            ; invoke clear_terminal and consume its documented result.
                                      leax      >Welcome,pcr                              ; advance the working pointer to the next redraw monitor prompt element.
                                      ldy       #$0023                                    ; fetch constant $0023 for the redraw monitor prompt calculation.
                                      lbsr      write_stdout_block                        ; invoke write_stdout_block and consume its documented result.
                                      leax      >MonTypes,pcr                             ; advance the working pointer to the next redraw monitor prompt element.
                                      ldy       #$001F                                    ; fetch constant $001F for the redraw monitor prompt calculation.
                                      lbsr      write_stdout_block                        ; invoke write_stdout_block and consume its documented result.
                                      leax      >MonTypeQ,pcr                             ; advance the working pointer to the next redraw monitor prompt element.
                                      ldy       #$001A                                    ; fetch constant $001A for the redraw monitor prompt calculation.
                                      lbsr      write_stdout_block                        ; invoke write_stdout_block and consume its documented result.
                                      clr       >monitor_type                             ; reset the working redraw monitor prompt value before reuse.
read_monitor_choice                   lbsr      read_key_nonblocking                      ; invoke read_key_nonblocking and consume its documented result.
                                      bcs       read_monitor_choice                       ; continue at read_monitor_choice when this state test selects that path.
                                      cmpa      #$63                                      ; test constant $63 to choose the next read monitor choice state.
                                      beq       finish_monitor_prompt                     ; continue at finish_monitor_prompt when this state test selects that path.
                                      cmpa      #$43                                      ; test constant $43 to choose the next read monitor choice state.
                                      beq       finish_monitor_prompt                     ; continue at finish_monitor_prompt when this state test selects that path.
                                      inc       >monitor_type                             ; advance the read monitor choice counter toward its next transition.
                                      cmpa      #$72                                      ; test constant $72 to choose the next read monitor choice state.
                                      beq       finish_monitor_prompt                     ; continue at finish_monitor_prompt when this state test selects that path.
                                      cmpa      #$52                                      ; test constant $52 to choose the next read monitor choice state.
                                      bne       redraw_monitor_prompt                     ; continue at redraw_monitor_prompt when this state test selects that path.
finish_monitor_prompt                 lbsr      clear_terminal                            ; invoke clear_terminal and consume its documented result.
                                      rts                                                 ; return the completed finish monitor prompt result to the caller.
write_stdout_block                    lda       >stdout_path                              ; fetch stdout_path for the write stdout block calculation.
                                      os9       I$Write                                   ; ask OS-9 to perform I$Write for this write stdout block operation.
                                      rts                                                 ; return the completed write stdout block result to the caller.

