* Normalizes OS-9 joystick coordinates and converts four threshold tests into active-low direction bits.
* The UI state machines consume those bits with hysteresis so selection does not chatter near center.
read_joystick_direction               ldd       #SS.Joy                                   ; fetch constant SS.Joy for the read joystick direction calculation.
                                      ldx       #$0001                                    ; fetch constant $0001 for the read joystick direction calculation.
                                      os9       I$GetStt                                  ; get joystick values
                                      tfr       y,d                                       ; reshape the working value/registers for read joystick direction arithmetic.
                                      lslb                                                ; rescale or extract packed read joystick direction bits for the next operation.
                                      tfr       d,y                                       ; reshape the working value/registers for read joystick direction arithmetic.
                                      tfr       x,d                                       ; reshape the working value/registers for read joystick direction arithmetic.
                                      lda       #$05                                      ; fetch constant $05 for the read joystick direction calculation.
                                      mul                                                 ; form the unsigned product used by the read joystick direction lookup or projection.
                                      lsra                                                ; rescale or extract packed read joystick direction bits for the next operation.
                                      rorb                                                ; rescale or extract packed read joystick direction bits for the next operation.
                                      tfr       d,x                                       ; reshape the working value/registers for read joystick direction arithmetic.
                                      stx       >ui_state_field_008                       ; commit the updated read joystick direction value to ui_state_field_008.
                                      sty       >ui_state_field_010                       ; commit the updated read joystick direction value to ui_state_field_010.
                                      exg       x,y                                       ; reshape the working value/registers for read joystick direction arithmetic.
                                      lda       #$FF                                      ; fetch constant $FF for the read joystick direction calculation.
                                      cmpx      #$007C                                    ; test constant $007C to choose the next read joystick direction state.
                                      bls       input_step_039                            ; continue at input_step_039 when this state test selects that path.
                                      anda      #$FE                                      ; apply the constant $FE mask/flags required by read joystick direction.
input_step_039                        cmpx      #$0006                                    ; test constant $0006 to choose the next input 039 state.
