play_single_tone                      pshs      u,y,x,b,a,cc                              ; save caller state so this one-shot tone helper is transparent.
                                      ldy       #$0E00                                    ; fetch constant $0E00 for the sound line disable calculation.
                                      ldx       #$2001                                    ; fetch constant $2001 for the sound line disable calculation.
                                      ldd       #$01*256+SS.Tone                          ; fetch constant $01*256+SS.Tone for the sound line disable calculation.
                                      os9       I$SetStt                                  ; play tone
                                      puls      pc,u,y,x,b,a,cc                           ; restore pc,u,y,x,b,a,cc; including PC returns when requested.
stop_sound                            lda       #$04                                      ; fetch constant $04 for the stop sound calculation.
* Interprets compact sound triplets until terminated, cancelled, or joystick-interrupted.
* Selects a sound stream by offset, then interprets three-byte duration/pitch events.
* Zero-duration records pause, sentinels stop/cancel, and joystick polling keeps long sequences interruptible.
play_sound_effect                     pshs      u,y,x,b                                   ; preserve u,y,x,b across the following play sound effect work.
                                      sta       >sound_request                            ; commit the updated play sound effect value to sound_request.
                                      lsla                                                ; rescale or extract packed play sound effect bits for the next operation.
                                      leay      >sound_sequence_table,pcr                 ; advance the working pointer to the next play sound effect element.
                                      ldd       a,y                                       ; fetch a,y for the play sound effect calculation.
                                      leau      d,y                                       ; advance the working pointer to the next play sound effect element.
                                      stu       >sound_stream_ptr                         ; commit the updated play sound effect value to sound_stream_ptr.
                                      bra       load_sound_stream                         ; continue at load_sound_stream when this state test selects that path.
cancel_sound_effect                   clr       >sound_request                            ; reset the working cancel sound effect value before reuse.
load_sound_stream                     ldu       >sound_stream_ptr                         ; fetch sound_stream_ptr for the load sound stream calculation.
sound_event_loop                      tst       >sound_request                            ; test sound_request to choose the next sound event loop state.
                                      bne       play_sound_event                          ; continue at play_sound_event when this state test selects that path.
                                      ldd       #SS.Joy                                   ; fetch constant SS.Joy for the sound event loop calculation.
                                      ldx       #$0001                                    ; fetch constant $0001 for the sound event loop calculation.
                                      pshs      u                                         ; preserve u across the following sound event loop work.
                                      os9       I$GetStt                                  ; get joystick values
                                      puls      u                                         ; restore u; including PC returns when requested.
                                      tsta                                                ; test  to choose the next sound event loop state.
                                      bne       finish_sound_effect                       ; continue at finish_sound_effect when this state test selects that path.
play_sound_event                      ldy       ,u                                        ; fetch ,u for the play sound event calculation.
                                      beq       process_sound_pause                       ; continue at process_sound_pause when this state test selects that path.
                                      cmpy      #$0001                                    ; test constant $0001 to choose the next play sound event state.
                                      beq       finish_sound_effect                       ; continue at finish_sound_effect when this state test selects that path.
                                      cmpy      #$0002                                    ; test constant $0002 to choose the next play sound event state.
                                      beq       cancel_sound_effect                       ; continue at cancel_sound_effect when this state test selects that path.
                                      lda       >tone_volume                              ; fetch tone_volume for the play sound event calculation.
                                      ldb       math_dp_field_02,u                        ; fetch math_dp_field_02,u for the play sound event calculation.
                                      tfr       d,x                                       ; reshape the working value/registers for play sound event arithmetic.
                                      pshs      u                                         ; preserve u across the following play sound event work.
                                      ldd       #$01*256+SS.Tone                          ; fetch constant $01*256+SS.Tone for the play sound event calculation.
                                      os9       I$SetStt                                  ; play tone
                                      puls      u                                         ; restore u; including PC returns when requested.
advance_sound_event                   leau      math_dp_field_03,u                        ; advance the working pointer to the next advance sound event element.
                                      bra       sound_event_loop                          ; continue at sound_event_loop when this state test selects that path.
finish_sound_effect                   puls      pc,u,y,x,b                                ; restore pc,u,y,x,b; including PC returns when requested.
process_sound_pause                   ldb       math_dp_field_02,u                        ; fetch math_dp_field_02,u for the process sound pause calculation.
                                      beq       advance_sound_event                       ; continue at advance_sound_event when this state test selects that path.
delay_sound_event                     ldx       #$01F4                                    ; fetch constant $01F4 for the delay sound event calculation.
delay_sound_tick                      leax      -$01,x                                    ; advance the working pointer to the next delay sound tick element.
                                      bne       delay_sound_tick                          ; continue at delay_sound_tick when this state test selects that path.
                                      decb                                                ; advance the delay sound tick counter toward its next transition.
                                      bne       delay_sound_event                         ; continue at delay_sound_event when this state test selects that path.
                                      bra       advance_sound_event                       ; continue at advance_sound_event when this state test selects that path.

